import{_ as i,o as a,c,ag as s}from"./chunks/framework.CAXxHpAX.js";const y=JSON.parse('{"title":"一战时间：1914-1918年","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-48.md","filePath":"notes/note-48.md"}'),l={name:"notes/note-48.md"};function v(r,d,e,o,t,n){return a(),c("div",null,[...d[0]||(d[0]=[s('<h1 id="一战时间-1914-1918年" tabindex="-1">一战时间：1914-1918年 <a class="header-anchor" href="#一战时间-1914-1918年" aria-label="Permalink to &quot;一战时间：1914-1918年&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、一战时间：</span>1914-1918年</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、三国同盟：</span>德意奥匈（失败） 三国协约：英法俄（胜利）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、一战根因：</span>帝国主义国家政治经济发展不平衡 直接原因：萨拉热窝事件</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、一战转折：</span>凡尔登战役。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、一战的性质：</span>帝国主义瓜分世界、争夺世界霸权的战争</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、一战的特点：</span>时间长、范围广、破坏性大。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、巴黎和会：</span>1919年 主导国：英、法、美 《凡尔赛条约》调整帝国主义在欧洲地区的关系</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>国际联盟（美国提出，英法操纵世界的工具，战败国、俄、美没加入）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、华盛顿会议：</span>1922年，主导国：美国 《九国公约》 调整帝国主义在亚太地区的关系</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、华盛顿会议的影响：</span>中国回到几个帝国主义国家共同支配的局面；美国实现“门户开放”政策。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、一战后的国际秩序：</span>凡尔赛—华盛顿体系</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、一战的影响：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①人类历史上一次规模空前的战争，造成巨大人力、物力损失。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②大大削弱了帝国主义的力量，根本上动摇了欧洲的优势地位。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>③削弱帝国主义的殖民力量，促进了殖民地半殖民地国家的民族觉醒。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>④列强忙于战争，暂时放松了对中国的经济侵略，有利于中国民族资本主义发展。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、二战的影响：</span>1939-1945年，第二次世界大战时人类历史上规模空前的战争，给人类文明造成巨大伤害。 第二次世界大战胜利的影响: 彻底粉碎了法西斯主义和军国主义通过战争称霸世界的野心，对维护世界和平、促进共同发展产生了重大而深远的影响。彻底结束了列强通过争夺殖民地瓜分世界的历史，促进了世界殖民体系的瓦解。</p></div><div class="circle-overlay"></div></div></div>',21)])])}const b=i(l,[["render",v]]);export{y as __pageData,b as default};
